('05378eb5-b671-4af7-81a3-ef4eab0e8fcc',	'Waitlist Registration',	'Register for Ultrade testnet waitlist',	'Waitlist',	NULL,	'Closed',	'8b9f4fc9-ae3b-4b43-ba70-d8eaa8677894',	'2026-04-23 10:03:42.151',	'2026-04-23 10:04:48.867',	'[{\"text\":\"Submit email: zhen@dkzhen.org\",\"image\":null,\"link\":null,\"isPrivate\":false},{\"text\":\"Submit personal details (name, country, etc.)\",\"image\":null,\"link\":null,\"isPrivate\":false},{\"text\":\"Confirmation received - registration complete\",\"image\":null,\"link\":null,\"isPrivate\":false}]',	'f8a34956-1784-4ffe-8e00-901a49e7b469'),
('0ec3efe0-9ad0-409e-ad3c-7f43925f7e89',	'Intake Assessment',	'The Cube must be destroyed.\n$1,000,000 to the one who strikes the final blow.\nDestroy blocks. Earn $CUBE. \nBuilt on @megaeth\nApply now >> megacorp [dot] global',	'Waitlist',	NULL,	'Open',	'07bdf725-5a1c-43f6-a18d-799cd374f4cb',	'2026-02-27 10:46:25.153',	'2026-02-27 10:48:12.360',	'[{\"link\": \"https://megacorp.global/rrs/intake\", \"text\": \"Register and fill survey\", \"image\": \"\"}, {\"link\": \"\", \"text\": \"Connect x account\", \"image\": \"\"}, {\"link\": \"\", \"text\": \"Submit new EVM wallet address\", \"image\": \"\"}, {\"link\": \"https://x.com/MegaCorpHQ/status/2023759348267446575\", \"text\": \"Source\", \"image\": \"\"}]',	NULL),
('1ee763c5-5d7f-429d-8d99-c910c6e530ec',	'Register App',	'Titan Airdrop FCFS\n5,000 $TITAN Tokens Up for Grabs!',	'App',	NULL,	'Open',	'1f91b429-6cf7-4603-b8f6-b845b6f0bf0e',	'2026-03-05 13:07:34.107',	'2026-03-05 13:08:18.723',	'[{\"link\": \"https://www.titanpay.vip/\", \"text\": \"register titan app\", \"image\": \"\"}, {\"link\": \"\", \"text\": \"Register With Email\", \"image\": \"\"}, {\"link\": \"https://titanpay.vip/register?inviteCode=HBKKYZ\", \"text\": \"invite code if you want HBKKYZ\", \"image\": \"\"}, {\"link\": \"\", \"text\": \"Complete kyc ( Bebas ngasal) \", \"image\": \"\"}]',	NULL),
('667a70e2-da32-4696-842a-6ff13a19188e',	'test',	'apa aja',	'tester',	NULL,	'Open',	'16fd08de-effc-4be0-9455-0050cf1c59de',	'2026-04-25 12:30:36.438',	'2026-04-25 12:30:36.438',	'[{\"text\":\"test\",\"image\":null,\"link\":\"https://devora.my.id/airdrops/16fd08de-effc-4be0-9455-0050cf1c59de\",\"isPrivate\":false}]',	'dcf0d194-9ca9-4d87-a369-fb09f9031efa'),
('6abb22bd-47f1-482a-ae9d-90af53450b9f',	'Waitlist Registration',	'Submit email to 3F waitlist via Webflow form.',	'Waitlist',	NULL,	'Open',	'6b25ee68-9e5a-4f8e-8d4e-aa2326074916',	'2026-04-25 04:49:33.608',	'2026-04-25 04:49:33.608',	'[{\"text\":\"Open 3F site: https://www.3f.xyz/\",\"image\":null,\"link\":\"https://www.3f.xyz/\",\"isPrivate\":false},{\"text\":\"Submit email: zhen@dkzhen.org\",\"image\":null,\"link\":null,\"isPrivate\":false},{\"text\":\"Backend response received: HTTP 200 {\\\"msg\\\":\\\"ok\\\",\\\"code\\\":200}\",\"image\":null,\"link\":null,\"isPrivate\":false},{\"text\":\"Req/res checked: Webflow endpoint accepts repeated submissions; no duplicate-email rejection detected.\",\"image\":null,\"link\":null,\"isPrivate\":false}]',	'f8a34956-1784-4ffe-8e00-901a49e7b469'),
('6c9863cc-ba7d-4758-8b5d-e5883424f70a',	'Waitlist Registration',	'Submit email to join Edel Canton waitlist',	'Waitlist',	NULL,	'Open',	'3ef8d140-9780-4d9e-bdd8-af7ca78314e8',	'2026-04-25 17:25:57.126',	'2026-04-25 17:25:57.126',	'[{\"text\":\"Visit https://canton.edel.finance/\",\"image\":null,\"link\":null,\"isPrivate\":false},{\"text\":\"Submit email: zhen@dkzhen.org\",\"image\":null,\"link\":null,\"isPrivate\":false},{\"text\":\"Waitlist registration complete\",\"image\":null,\"link\":null,\"isPrivate\":false}]',	'f8a34956-1784-4ffe-8e00-901a49e7b469'),
('6f586d46-4c03-4dbd-97a5-0060128560bd',	'Join email waitlist Nava AI',	'Submit email ke https://navalabs.ai untuk masuk daftar tunggu early access. Saat ini hanya email, belum ada task onchain atau token. Email yang didaftarkan: zhen@dkzhen.org',	'Waitlist',	NULL,	'Open',	'5a9e02cd-17b2-411c-b772-283fc4ff2181',	'2026-04-16 06:52:46.502',	'2026-04-16 06:52:46.502',	'[{\"text\":\"Buka https://navalabs.ai dan submit email di kolom form.\",\"image\":null,\"link\":null,\"isPrivate\":false},{\"text\":\"Konfirmasi email diterima di website (ada notifikasi muncul).\",\"image\":null,\"link\":null,\"isPrivate\":false},{\"text\":\"Catat email yang sudah didaftarkan: zhen@dkzhen.org\",\"image\":null,\"link\":null,\"isPrivate\":true}]',	'f8a34956-1784-4ffe-8e00-901a49e7b469'),
('7774793a-20e2-4c34-9861-e75a09fe9c38',	'Community Contributor Program',	'Aro announced the launch of a contributor program. You can create content, help newcomers, or give feedback to earn unique roles and badges.\n\nBasic condition for participation: you must obtain the role of \"Guardian\" (reach level 15 on the project\'s Discord server).\n\nThe program features three unique contributor roles:\n• Aro Creator: creating 3–5 high-quality posts about the ecosystem per week, primarily on X/Twitter. Minimum 2 weeks.\n• Aro Gem: providing constructive feedback, finding bugs, and suggesting improvements. 5-10 useful reports in 2-3 weeks. \n• Aro Yapper: maintaining high-quality discussions and helping newcomers in chat rooms. Consistent activity for 7-14 days',	'Social',	NULL,	'Open',	'ae722871-34ba-4bbf-8722-bc70ed0d4f75',	'2026-02-26 10:52:24.916',	'2026-02-26 10:52:24.916',	'[{\"link\": \"https://discord.gg/PdmtcnN4t6\", \"text\": \"Go to the project\'s Discord and reach level 15. The level is achieved through communication in the chat\", \"image\": \"\"}, {\"link\": \"\", \"text\": \"Complete the conditions corresponding to the selected direction.\", \"image\": \"\"}, {\"link\": \"\", \"text\": \"Apply for the role of contributor in the contributor-application thread, attaching a link to your work. The contributor-application thread is only open on the 15th and 30th of each month.\", \"image\": \"\"}]',	NULL),
('89cd2f9b-1970-4293-baa4-5fbf8766300b',	'Social Media Tasks',	'Follow Edel Finance on social media platforms',	'Social',	NULL,	'Open',	'3ef8d140-9780-4d9e-bdd8-af7ca78314e8',	'2026-04-25 17:25:57.555',	'2026-04-25 17:25:57.555',	'[{\"text\":\"Follow @edeldotfinance on Twitter: https://x.com/edeldotfinance\",\"image\":null,\"link\":null,\"isPrivate\":false},{\"text\":\"Join Telegram: https://t.me/edelfinance\",\"image\":null,\"link\":null,\"isPrivate\":false},{\"text\":\"Join Discord: https://discord.com/invite/edel\",\"image\":null,\"link\":null,\"isPrivate\":false}]',	'f8a34956-1784-4ffe-8e00-901a49e7b469'),
